class ProtectedDataResponse(BaseModel):
    data: str
    user: UserResponse
    timestamp: str


class AdminResponse(BaseModel):
    admin_data: str
    user: UserResponse
    all_users_count: int


# Security scheme
security = HTTPBearer()


# Token validation dependency
async def validate_token(
    credentials: HTTPAuthorizationCredentials = Security(security),
    redis_client: redis.Redis = Depends(get_redis),
) -> TokenData:
    """
    Dependency that validates OAuth 2.0 bearer tokens by checking Redis cache.
    Extracts the token from the Authorization header and looks it up in Redis.
    """
    token = credentials.credentials

    if not token:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Missing bearer token",
            headers={"WWW-Authenticate": "Bearer"},
        )

    try:
        token_key = f"{TOKEN_PREFIX}{token}"
        token_data_raw = await redis_client.hgetall(token_key)

        if not token_data_raw:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        # Check expiration
        expires_at = token_data_raw.get("expires_at", "")
        if expires_at:
            expiry_time = datetime.fromisoformat(expires_at)
            if datetime.utcnow() > expiry_time:
                # Clean up expired token
                await redis_client.delete(token_key)
                raise HTTPException(
                    status_code=status.HTTP_401_UNAUTHORIZED,
                    detail="Token has expired",
                    headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
                )

        scopes_str = token_data_raw.get("scopes", "")
        scopes = scopes_str.split(",") if scopes_str else []

        token_data = TokenData(
            user_id=token_data_raw["user_id"],
            email=token_data_raw["email"],
            scopes=scopes,
            expires_at=expires_at,
            client_id=token_data_raw.get("client_id", "unknown"),
        )

        return token_data

    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Token validation service unavailable: {str(e)}",
        )
    except KeyError as e:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail=f"Malformed token data in cache: missing {str(e)}",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )


# Scope-based authorization dependency factory
def require_scopes(*required_scopes: str):
    """Factory that creates a dependency to check for required OAuth scopes."""

    async def scope_checker(
        token_data: TokenData = Depends(validate_token),
    ) -> TokenData:
        for scope in required_scopes:
            if scope not in token_data.scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scope. Required: {', '.join(required_scopes)}. "
                    f"Granted: {', '.join(token_data.scopes)}",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope" '
                        f'scope="{" ".join(required_scopes)}"'
                    },
                )
        return token_data

    return scope_checker


# Lifespan management
@asynccontextmanager
async def lifespan(app: FastAPI):
    # Startup: initialize Redis connection
    global redis_pool
    redis_pool = redis.from_url(
        REDIS_URL,
        encoding="utf-8",
        decode_responses=True,
        max_connections=50,
    )
    # Verify connection
    try:
        await redis_pool.ping()
        print("✅ Connected to Redis successfully")
    except redis.RedisError as e:
        print(f"⚠️ Redis connection failed: {e}")

    yield

    # Shutdown: close Redis connection
    if redis_pool:
        await redis_pool.close()
        print("🔌 Redis connection closed")


# FastAPI application
app = FastAPI(
    title="OAuth 2.0 Token Validation API",
    description="High-performance API with Redis-backed OAuth 2.0 token validation",
    version="1.0.0",
    lifespan=lifespan,
)


# --- Public endpoints ---


@app.get("/health", response_model=HealthResponse)
async def health_check():
    """Health check endpoint - no authentication required."""
    redis_connected = False
    try:
        client = await get_redis()
        await client.ping()
        redis_connected = True
    except Exception:
        pass

    return HealthResponse(
        status="healthy" if redis_connected else "degraded",
        redis_connected=redis_connected,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.post("/tokens", response_model=MessageResponse, status_code=status.HTTP_201_CREATED)
async def register_token(
    token_info: TokenInfo,
    redis_client: redis.Redis = Depends(get_redis),
):
    """
    Register a token in Redis cache (simulating what an OAuth server would do).
    In production, this would be done by your OAuth 2.0 authorization server.
    """
    token_key = f"{TOKEN_PREFIX}{token_info.access_token}"
    expires_at = (
        datetime.utcnow() + timedelta(seconds=token_info.expires_in)
    ).isoformat()

    token_data = {
        "user_id": token_info.user_id,
        "email": token_info.email,
        "scopes": ",".join(token_info.scopes),
        "client_id": token_info.client_id,
        "expires_at": expires_at,
        "created_at": datetime.utcnow().isoformat(),
    }

    try:
        await redis_client.hset(token_key, mapping=token_data)
        await redis_client.expire(token_key, token_info.expires_in)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Failed to store token: {str(e)}",
        )

    return MessageResponse(message=f"Token registered successfully, expires at {expires_at}")


@app.delete("/tokens/{access_token}", response_model=MessageResponse)
async def revoke_token(
    access_token: str,
    redis_client: redis.Redis = Depends(get_redis),
):
    """Revoke (delete) a token from Redis cache."""
    token_key = f"{TOKEN_PREFIX}{access_token}"
    deleted = await redis_client.delete(token_key)
    if not deleted:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found",
        )
    return MessageResponse(message="Token revoked successfully")


