@app.get("/admin/dashboard", response_model=AdminResponse)
async def admin_dashboard(
    token_data: TokenData = Depends(require_scopes("admin")),
    redis_client: redis.Redis = Depends(get_redis),
):
    """Admin-only endpoint requiring 'admin' scope."""
    # Count all active tokens in Redis
    cursor = 0
    count = 0
    while True:
        cursor, keys = await redis_client.scan(
            cursor=cursor, match=f"{TOKEN_PREFIX}*", count=100
        )
        count += len(keys)
        if cursor == 0:
            break

    return AdminResponse(
        admin_data="Admin dashboard data",
        user=UserResponse(
            user_id=token_data.user_id,
            email=token_data.email,
            scopes=token_data.scopes,
            client_id=token_data.client_id,
        ),
        all_users_count=count,
    )


